  p_Name_85a3d045 := 'ExternalChangeDetection_DetectUpdates';
  p_CategoryID_85a3d045 := 'FE1AE5B2-FC57-43B2-B560-A673713E1679';
  p_Description_85a3d045 := 'Detects updated records in an external system by comparing UpdatedAt timestamps.';
  p_SQL_85a3d045 := '-- T-SQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot.[{{ UpdatedAtField }}] AS UpdatedAt, rc.last_change_time LatestRecordChangeAt
FROM 
    [{{ SchemaName }}].[{{ BaseView }}] ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        [__mj].vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE 
    ot.[{{ UpdatedAtField }}] > COALESCE(rc.last_change_time, ''1900-01-01 00:00:00.000'');
';
