-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_ID_682c16a7 UUID;
  p_QueryID_682c16a7 UUID;
  p_SQLDialectID_682c16a7 UUID;
  p_SQL_682c16a7 TEXT;
BEGIN
  p_ID_682c16a7 := 'd85de0ad-5b5b-4ef4-82bc-c634ce39e836';
  p_QueryID_682c16a7 := '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57';
  p_SQLDialectID_682c16a7 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_682c16a7 := '-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT 
    {{ ColumnList }}, ot."{{ CreatedAtField }}" AS "CreatedAt", ot."{{ UpdatedAtField }}" AS "UpdatedAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN 
    [__mj].vwRecordChanges rc 
    ON 
    ({{ PrimaryKeyJoin }} = rc."RecordID") AND 
    rc."Type" = ''Create'' AND 
    rc."EntityID" = {{ EntityID | sqlString }} 
WHERE 
    rc."RecordID" IS NULL;
';
  PERFORM __mj."spCreateQuerySQL"(p_ID := p_ID_682c16a7, p_QueryID := p_QueryID_682c16a7, p_SQLDialectID := p_SQLDialectID_682c16a7, p_SQL := p_SQL_682c16a7);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_ID_8a979854 UUID;
  p_QueryID_8a979854 UUID;
  p_SQLDialectID_8a979854 UUID;
  p_SQL_8a979854 TEXT;
BEGIN
  p_ID_8a979854 := '565c5af3-5f59-4531-b21d-53ebc884ef5b';
  p_QueryID_8a979854 := '46A91235-2122-40E8-9289-20D04489CAC5';
  p_SQLDialectID_8a979854 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_8a979854 := '-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot."{{ UpdatedAtField }}" AS "UpdatedAt", rc.last_change_time AS "LatestRecordChangeAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        [__mj].vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE 
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ));
';
  PERFORM __mj."spCreateQuerySQL"(p_ID := p_ID_8a979854, p_QueryID := p_QueryID_8a979854, p_SQLDialectID := p_SQLDialectID_8a979854, p_SQL := p_SQL_8a979854);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_ID_062985da UUID;
  p_QueryID_062985da UUID;
  p_SQLDialectID_062985da UUID;
  p_SQL_062985da TEXT;
BEGIN
  p_ID_062985da := 'f325dcbe-347f-4f59-9a8a-a18706803c8b';
  p_QueryID_062985da := '028A39F6-2B38-4ED1-8235-4671B7CD330B';
  p_SQLDialectID_062985da := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_062985da := '-- PostgreSQL variant for External Change Detection - Detect Deletions
-- TECHNICAL DEBT: Joining on dynamically generated PrimaryKeyJoin (a concatenated string) prevents
-- the use of indexes on the organic table (ot). For massive tables, this will result in a table scan.
-- A future schema change to separate RecordID parts into native columns is recommended.
SELECT 
    rc."RecordID", MAX(rc."ChangedAt") AS "ChangedAt"
FROM 
    [__mj].vwRecordChanges rc
LEFT JOIN 
    "{{ SchemaName }}"."{{ BaseView }}" ot 
    ON 
    rc."RecordID" = {{ PrimaryKeyJoin }}
WHERE 
    {{ PrimaryKeyIsNull }}
    AND 
        rc."EntityID" = {{ EntityID | sqlString }} 
    AND 
        rc."Type" <> ''Delete''
GROUP BY 
    rc."RecordID"
HAVING 
    MAX(CASE WHEN rc."Type" = ''Delete'' THEN 1 ELSE 0
END) = 0;
';
  PERFORM __mj."spCreateQuerySQL"(p_ID := p_ID_062985da, p_QueryID := p_QueryID_062985da, p_SQLDialectID := p_SQLDialectID_062985da, p_SQL := p_SQL_062985da);
END $$;
